// Pack an array of 16 boolean coil values into a single 16-bit register
const coils = msg.payload.data;
let register = 0;
for (let i = 0; i < Math.min(coils.length, 16); i++) {
    if (coils[i]) {
        register |= (1 << i);  // Bit 0 = Coil 0 (LSB)
    }
}
msg.payload = register;
msg.binaryString = register.toString(2).padStart(16, '0');
msg.topic = 'coils/packed';
return msg;

// Unpack a 16-bit register into named bit flags
// Customize the labels array for your application
const LABELS = [
    'Motor Running',    // Bit 0
    'Pump Active',      // Bit 1
    'Valve Open',       // Bit 2
    'Heater On',        // Bit 3
    'Alarm Active',     // Bit 4
    'Emergency Stop',   // Bit 5
    'Sensor Fault',     // Bit 6
    'Comm Error',       // Bit 7
    'Reserved_8',       // Bit 8
    'Reserved_9',       // Bit 9
    'Reserved_10',      // Bit 10
    'Reserved_11',      // Bit 11
    'Reserved_12',      // Bit 12
    'Reserved_13',      // Bit 13
    'Reserved_14',      // Bit 14
    'Reserved_15'       // Bit 15
];

const register = msg.payload.data[0];
const bits = {};
const activeBits = [];

for (let i = 0; i < 16; i++) {
    const isSet = (register & (1 << i)) !== 0;
    bits[LABELS[i]] = isSet;
    if (isSet) activeBits.push(LABELS[i]);
}

msg.payload = {
    raw: register,
    binary: register.toString(2).padStart(16, '0'),
    flags: bits,
    active: activeBits
};
msg.topic = 'status/flags';
return msg;
